        <div class="col-12 col-md-4">
            <label class="form-label">شروع دوره (شمسی)</label>
            <InputText class="form-control" @bind-Value="_model.PeriodStart" placeholder="1404/01/01" />
        </div>

        <div class="col-12 col-md-4">
            <label class="form-label">پایان دوره (شمسی)</label>
            <InputText class="form-control" @bind-Value="_model.PeriodEnd" placeholder="1404/01/01" />
        </div>

        <div class="col-12">
            <div class="d-flex align-items-center justify-content-between mb-2">
                <label class="form-label mb-0">نکات برجسته</label>
                <button type="button" class="btn btn-sm btn-outline-secondary" @onclick="AddHighlight">
                    <i class="bi bi-plus-lg"></i> افزودن
                </button>
            </div>

            <div class="d-grid gap-2">
                @for (var i = 0; i < _model.Highlights.Count; i++)
                {
                    var index = i;
                    var highlight = _model.Highlights[index];
                    <div class="border rounded-3 p-3 bg-light" @key="index">
                        <div class="row g-2 align-items-end">
                            <div class="col-12 col-md-7">
                                <label class="form-label small">متن</label>
                                <InputText class="form-control" @bind-Value="highlight.Text" placeholder="متن نکته" />
                            </div>
                            <div class="col-8 col-md-3">
                                <label class="form-label small">نوع</label>
                                <InputSelect TValue="ReportHighlightType" class="form-select" @bind-Value="highlight.Type">
                                    <option value="@ReportHighlightType.Positive">مثبت</option>
                                    <option value="@ReportHighlightType.Negative">منفی</option>
                                    <option value="@ReportHighlightType.Lesson">درس‌آموخته</option>
                                </InputSelect>
                            </div>
                            <div class="col-4 col-md-2 text-end">
                                <button type="button" class="btn btn-outline-danger w-100" @onclick="() => RemoveHighlight(index)" disabled="@(_model.Highlights.Count == 1)">
                                    <i class="bi bi-trash3"></i>
                                </button>
                            </div>
                        </div>
                    </div>
                }
            </div>
        </div>

        <div class="col-12 pt-2">
            <button type="submit" class="btn btn-primary w-100" disabled="@_isLoading">
                @if (_isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-2"></span>
                    <span>در حال ذخیره...</span>
                }
                else
                {
                    <span>@(_reportId.HasValue ? "به‌روزرسانی گزارش" : "ثبت گزارش")</span>
                }
            </button>
        </div>
    </div>
</EditForm>

@code {
    [Parameter] public Guid? ReportId { get; set; }
    [Parameter] public DateTimeOffset DefaultPeriodStart { get; set; } = DateTimeOffset.Now.Date;
    [Parameter] public DateTimeOffset DefaultPeriodEnd { get; set; } = DateTimeOffset.Now.Date;
    [Parameter] public ReportEditorModel? InitialModel { get; set; }
    [Parameter] public EventCallback OnSaved { get; set; }

    private ReportEditorModel _model = new();
    private EditContext? _editContext;
    private bool _isLoading;

    protected override void OnParametersSet()
    {
        if (_editContext is not null)
            return;

        _model = InitialModel?.Clone() ?? new ReportEditorModel
        {
            PeriodStart = DefaultPeriodStart.ToPersianDate(),
            PeriodEnd = DefaultPeriodEnd.ToPersianDate(),
            Highlights = [new ReportHighlightModel()]
        };

        if (!_model.Highlights.Any())
            _model.Highlights.Add(new ReportHighlightModel());

        _editContext = new EditContext(_model);
    }

    private void AddHighlight()
    {
        _model.Highlights.Add(new ReportHighlightModel());
        _editContext?.NotifyFieldChanged(new FieldIdentifier(_model, nameof(ReportEditorModel.Highlights)));
    }

    private void RemoveHighlight(int index)
    {
        if (_model.Highlights.Count <= 1)
            return;

        _model.Highlights.RemoveAt(index);
        _editContext?.NotifyFieldChanged(new FieldIdentifier(_model, nameof(ReportEditorModel.Highlights)));
    }

    private async Task HandleSubmit()
    {
        if (_isLoading)
            return;

        _isLoading = true;

        if (_editContext is null || !_editContext.Validate())
        {
            _isLoading = false;
            return;
        }

        var periodStart = PersianDateHelper.ToGregorianDateTime(_model.PeriodStart);
        if (!periodStart.HasValue)
        {
            ToastService.ShowToastError("تاریخ شروع معتبر نیست!");
            _isLoading = false;
            return;
        }

        var periodEnd = PersianDateHelper.ToGregorianDateTime(_model.PeriodEnd);
        if (!periodEnd.HasValue)
        {
            ToastService.ShowToastError("تاریخ پایان معتبر نیست!");
            _isLoading = false;
            return;
        }

        if (periodEnd.Value.Date < periodStart.Value.Date)
        {
            ToastService.ShowToastError("تاریخ پایان نمی‌تواند قبل از تاریخ شروع باشد!");
            _isLoading = false;
            return;
        }

        var highlights = _model.Highlights
            .Where(x => !string.IsNullOrWhiteSpace(x.Text))
            .Select(x => new ReportHighlightDto(x.Text.Trim(), x.Type))
            .ToList();

        if (ReportId.HasValue)
        {
            var request = new UpdateReportRequest(
                Title: string.IsNullOrWhiteSpace(_model.Title) ? null : _model.Title.Trim(),
                Note: _model.Note.Trim(),
                Score: _model.Score,
                PeriodStart: DateOnly.FromDateTime(periodStart.Value.DateTime),
                PeriodEnd: DateOnly.FromDateTime(periodEnd.Value.DateTime),
                Highlights: highlights);

            var result = await ApiService.SendAsync(
                apiCall: () => ApiClient.ReportsPUTAsync(ReportId.Value, request),
                successMessage: "گزارش با موفقیت به‌روزرسانی شد!",
                showErrorToast: true);

            if (result?.IsSuccess is true)
                await OnSaved.InvokeAsync();
        }
        else
        {
            var request = new CreateReportRequest(
                Title: string.IsNullOrWhiteSpace(_model.Title) ? null : _model.Title.Trim(),
                Note: _model.Note.Trim(),
                Score: _model.Score,
                PeriodStart: DateOnly.FromDateTime(periodStart.Value.DateTime),
                PeriodEnd: DateOnly.FromDateTime(periodEnd.Value.DateTime),
                Highlights: highlights);

            var result = await ApiService.SendAsync(
                apiCall: () => ApiClient.ReportsPOSTAsync(request),
                successMessage: "گزارش با موفقیت ثبت شد!",
                showErrorToast: true);

            if (result?.IsSuccess is true)
                await OnSaved.InvokeAsync();
        }

        _isLoading = false;
    }
}

using System.Globalization;

namespace SamarPlanner.Web.Helpers;

public enum ReportPeriodView
{
    Daily,
    Weekly,
    Monthly,
    Yearly
}

public static class ReportPeriodHelper
{
    private static readonly PersianCalendar PersianCalendar = new();

    public static bool TryParse(string? value, out ReportPeriodView period)
    {
        period = ReportPeriodView.Daily;

        if (string.IsNullOrWhiteSpace(value))
            return false;

        return value.Trim().ToLowerInvariant() switch
        {
            "daily" or "day" => SetPeriod(ReportPeriodView.Daily, out period),
            "weekly" or "week" => SetPeriod(ReportPeriodView.Weekly, out period),
            "monthly" or "month" => SetPeriod(ReportPeriodView.Monthly, out period),
            "yearly" or "year" => SetPeriod(ReportPeriodView.Yearly, out period),
            _ => false
        };
    }

    public static ReportPeriodView ParseOrDefault(string? value)
    {
        return TryParse(value, out var period) ? period : ReportPeriodView.Daily;
    }

    public static string ToRouteSegment(this ReportPeriodView period)
    {
        return period switch
        {
            ReportPeriodView.Daily => "daily",
            ReportPeriodView.Weekly => "weekly",
            ReportPeriodView.Monthly => "monthly",
            ReportPeriodView.Yearly => "yearly",
            _ => "daily"
        };
    }

    public static string ToDisplayName(this ReportPeriodView period)
    {
        return period switch
        {
            ReportPeriodView.Daily => "روزانه",
            ReportPeriodView.Weekly => "هفتگی",
            ReportPeriodView.Monthly => "ماهانه",
            ReportPeriodView.Yearly => "سالانه",
            _ => "روزانه"
        };
    }

    public static (DateTimeOffset Start, DateTimeOffset End) GetBounds(ReportPeriodView period, DateTimeOffset reference)
    {
        var dt = reference.DateTime;
        var year = PersianCalendar.GetYear(dt);
        var month = PersianCalendar.GetMonth(dt);
        var day = PersianCalendar.GetDayOfMonth(dt);

        return period switch
        {
            ReportPeriodView.Daily => (reference.Date, reference.Date),
            ReportPeriodView.Weekly => GetWeekBounds(reference),
            ReportPeriodView.Monthly => GetMonthBounds(year, month),
            ReportPeriodView.Yearly => GetYearBounds(year),
            _ => (reference.Date, reference.Date)
        };
    }

    public static DateTimeOffset ShiftReference(ReportPeriodView period, DateTimeOffset reference, int direction)
    {
        return period switch
        {
            ReportPeriodView.Daily => reference.AddDays(direction),
            ReportPeriodView.Weekly => reference.AddDays(direction * 7),
            ReportPeriodView.Monthly => reference.AddMonths(direction),
            ReportPeriodView.Yearly => reference.AddYears(direction),
            _ => reference.AddDays(direction)
        };
    }

    public static string GetPeriodLabel(ReportPeriodView period, DateTimeOffset start, DateTimeOffset end)
    {
        return period == ReportPeriodView.Daily
            ? start.ToPersianDate()
            : $"{start.ToPersianDate()} - {end.ToPersianDate()}";
    }

    private static (DateTimeOffset Start, DateTimeOffset End) GetWeekBounds(DateTimeOffset reference)
    {
        var daysSinceSaturday = ((int)reference.DayOfWeek - (int)DayOfWeek.Saturday + 7) % 7;
        var start = reference.AddDays(-daysSinceSaturday).Date;
        var end = start.AddDays(6);
        return (start, end);
    }

    private static (DateTimeOffset Start, DateTimeOffset End) GetMonthBounds(int year, int month)
    {
        var start = FromPersianDate(year, month, 1);
        var lastDay = PersianCalendar.GetDaysInMonth(year, month);
        var end = FromPersianDate(year, month, lastDay);
        return (start, end);
    }

    private static (DateTimeOffset Start, DateTimeOffset End) GetYearBounds(int year)
    {
        var start = FromPersianDate(year, 1, 1);
        var end = FromPersianDate(year, 12, 29);

        try
        {
            end = FromPersianDate(year, 12, PersianCalendar.GetDaysInMonth(year, 12));
        }
        catch
        {
            // In rare calendar edge cases, keep the default end date.
        }

        return (start, end);
    }

    private static DateTimeOffset FromPersianDate(int year, int month, int day)
    {
        var dateTime = PersianCalendar.ToDateTime(year, month, day, 0, 0, 0, 0);
        return new DateTimeOffset(dateTime, TimeSpan.Zero);
    }

    private static bool SetPeriod(ReportPeriodView value, out ReportPeriodView period)
    {
        period = value;
        return true;
    }
}

