    private static (DateTimeOffset Start, DateTimeOffset End) GetMonthBounds(int year, int month)
    {
        var start = FromPersianDate(year, month, 1);
        var end = month switch
        {
            <= 6 => FromPersianDate(year, month, 31),
            <= 11 => FromPersianDate(year, month, 30),
            _ => TryCreateDate(year, month, 30) ?? FromPersianDate(year, month, 29)
        };
        return (start, end);
    }

    private static (DateTimeOffset Start, DateTimeOffset End) GetYearBounds(int year)
    {
        var start = FromPersianDate(year, 1, 1);
        var end = TryCreateDate(year, 12, 30) ?? FromPersianDate(year, 12, 29);

        return (start, end);
    }

    private static DateTimeOffset FromPersianDate(int year, int month, int day)
    {
        var dateTime = PersianCalendar.ToDateTime(year, month, day, 0, 0, 0, 0);
        return new DateTimeOffset(dateTime, TimeSpan.Zero);
    }

    private static DateTimeOffset? TryCreateDate(int year, int month, int day)
    {
        try
        {
            return FromPersianDate(year, month, day);
        }
        catch
        {
            return null;
        }
    }

    private static bool SetPeriod(ReportPeriodView value, out ReportPeriodView period)
    {
        period = value;
        return true;
    }
}

@inherits LayoutComponentBase
@using Blazored.Toast
@using Blazored.Toast.Configuration
@using Microsoft.AspNetCore.WebUtilities
@using SamarPlanner.Web.Helpers
@using SamarPlanner.Web.Services
@inject NavigationManager NavigationManager

<div class="report-layout">
	<div class="report-header">
		<div class="report-nav">
			<NavLink href="/reports/daily" class="nav-link" ActiveClass="active" Match="NavLinkMatch.Prefix">
				<i class="bi bi-calendar-day"></i> روزانه
			</NavLink>
			<NavLink href="/reports/weekly" class="nav-link" ActiveClass="active" Match="NavLinkMatch.Prefix">
				<i class="bi bi-calendar-week"></i> هفتگی
			</NavLink>
			<NavLink href="/reports/monthly" class="nav-link" ActiveClass="active" Match="NavLinkMatch.Prefix">
				<i class="bi bi-calendar-month"></i> ماهانه
			</NavLink>
			<NavLink href="/reports/yearly" class="nav-link" ActiveClass="active" Match="NavLinkMatch.Prefix">
				<i class="bi bi-calendar3"></i> سالانه
			</NavLink>
		</div>
	</div>

	<main class="report-content">
		@Body
	</main>

	<div class="fab-container">
		<button class="btn-fab" @onclick="OpenAddReportModal">
			<i class="bi bi-plus-lg"></i>
		</button>
	</div>
</div>

@if (_showAddReportModal)
{
	<div class="modal-overlay" @onclick="CloseModal">
		<div class="modal-content" @onclick:stopPropagation>
			<div class="modal-header">
				<h5>گزارش جدید</h5>
				<button class="btn-close" @onclick="CloseModal"></button>
			</div>
			<div class="modal-body">
				<ReportForm DefaultPeriodStart="_defaultPeriodStart"
							DefaultPeriodEnd="_defaultPeriodEnd"
							OnSaved="OnReportSaved" />
			</div>
		</div>
	</div>
}

<BlazoredToasts Position="ToastPosition.TopRight" />

@code {
	private bool _showAddReportModal;
	private DateTimeOffset _defaultPeriodStart = DateTimeOffset.Now.Date;
	private DateTimeOffset _defaultPeriodEnd = DateTimeOffset.Now.Date;

	private void OpenAddReportModal()
	{
		SetDefaultPeriodContext();
		_showAddReportModal = true;
	}

	private void CloseModal()
	{
		_showAddReportModal = false;
	}

	private Task OnReportSaved()
	{
		CloseModal();
		NavigationManager.NavigateTo(NavigationManager.Uri, forceLoad: true);
		return Task.CompletedTask;
	}

	private void SetDefaultPeriodContext()
	{
		var uri = NavigationManager.ToAbsoluteUri(NavigationManager.Uri);
		var queryParams = QueryHelpers.ParseQuery(uri.Query);

		var period = GetCurrentPeriod(uri, queryParams);
		var referenceDate = GetReferenceDate(queryParams);
		(_defaultPeriodStart, _defaultPeriodEnd) = ReportPeriodHelper.GetBounds(period, referenceDate);
	}

	private static ReportPeriodView GetCurrentPeriod(Uri uri, IDictionary<string, Microsoft.Extensions.Primitives.StringValues> queryParams)
	{
		if (queryParams.TryGetValue("period", out var periodValue) && ReportPeriodHelper.TryParse(periodValue.ToString(), out var period))
			return period;

		var pathSegment = uri.AbsolutePath.Trim('/').Split('/', StringSplitOptions.RemoveEmptyEntries).LastOrDefault();
		return ReportPeriodHelper.ParseOrDefault(pathSegment);
	}

	private static DateTimeOffset GetReferenceDate(IDictionary<string, Microsoft.Extensions.Primitives.StringValues> queryParams)
	{
		if (queryParams.TryGetValue("date", out var dateValue) && !string.IsNullOrWhiteSpace(dateValue))
		{
			var parsed = PersianDateHelper.ToGregorianDateTime(dateValue.ToString());
			if (parsed.HasValue)
				return parsed.Value;
		}

		return DateTimeOffset.Now;
	}
}

/* Layout/ReportLayout.razor.css */

.report-layout {
	display: flex;
	flex-direction: column;
	min-height: 100vh;
	background: #f8f9fa;
}

.report-header {
	background: white;
	padding: 12px 16px;
	border-bottom: 1px solid #e9ecef;
	position: sticky;
	top: 0;
	z-index: 100;
	box-shadow: 0 2px 8px rgba(0, 0, 0, 0.03);
}

.report-nav {
	display: flex;
	gap: 6px;
	justify-content: center;
	max-width: 560px;
	margin: 0 auto;
	align-items: center;
	flex-wrap: wrap;
}

.report-nav .nav-link {
	padding: 10px 20px;
	border-radius: 50px;
	font-size: 0.9rem;
	font-weight: 500;
	color: #6c757d;
	transition: all 0.25s ease;
	text-decoration: none;
	position: relative;
	background: transparent;
	border: 1px solid transparent;
	display: flex;
	align-items: center;
	gap: 6px;
}

.report-nav .nav-link i {
	font-size: 1.1rem;
}

.report-nav .nav-link:hover:not(.active) {
	background: #f1f3f5;
	color: #1a1a2e;
	transform: translateY(-1px);
}

.report-nav .nav-link.active {
	background: linear-gradient(135deg, #0d6efd, #0a58ca);
	color: white;
	box-shadow: 0 4px 16px rgba(13, 110, 253, 0.3);
	border-color: #0d6efd;
}

.report-nav .nav-link.active:hover {
	box-shadow: 0 6px 24px rgba(13, 110, 253, 0.4);
	transform: translateY(-1px);
}

.report-content {
	flex: 1;
	padding: 16px;
	max-width: 720px;
	width: 100%;
	margin: 0 auto;
	padding-bottom: 100px;
}

.fab-container {
	position: fixed;
	bottom: 28px;
	right: 28px;
	z-index: 999;
}

.btn-fab {
	width: 64px;
	height: 64px;
	border-radius: 50%;
	background: linear-gradient(135deg, #0d6efd, #0a58ca);
	border: none;
	color: white;
	font-size: 2rem;
	display: flex;
	align-items: center;
	justify-content: center;
	box-shadow: 0 8px 28px rgba(13, 110, 253, 0.35);
	transition: all 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
	cursor: pointer;
	outline: none;
}

.btn-fab:hover {
	transform: scale(1.06);
	box-shadow: 0 12px 36px rgba(13, 110, 253, 0.45);
}

.btn-fab:active {
	transform: scale(0.92);
}

.modal-overlay {
	position: fixed;
	top: 0;
	left: 0;
	right: 0;
	bottom: 0;
	background: rgba(0, 0, 0, 0.4);
	backdrop-filter: blur(6px);
	z-index: 1050;
	display: flex;
	align-items: center;
	justify-content: center;
	padding: 20px;
}

.modal-content {
	background: white;
	border-radius: 24px;
	max-width: 560px;
	width: 100%;
	max-height: 90vh;
	overflow-y: auto;
	padding: 28px 24px;
	animation: slideUp 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

@keyframes slideUp {
	from {
		opacity: 0;
		transform: translateY(30px) scale(0.97);
	}
	to {
		opacity: 1;
		transform: translateY(0) scale(1);
	}
}

.modal-header {
	display: flex;
	justify-content: space-between;
	align-items: center;
	margin-bottom: 20px;
	padding-bottom: 12px;
	border-bottom: 1px solid #f0f2f5;
}

.modal-header h5 {
	font-weight: 700;
	margin: 0;
	font-size: 1.15rem;
	color: #1a1a2e;
}

.modal-header .btn-close {
	background: transparent;
	border: none;
	font-size: 1.4rem;
	color: #6c757d;
	cursor: pointer;
	padding: 4px 8px;
	border-radius: 8px;
	transition: background 0.15s ease;
}

.modal-header .btn-close:hover {
	background: #f1f3f5;
	color: #1a1a2e;
}

@media (max-width: 576px) {
	.report-nav .nav-link {
		padding: 8px 14px;
		font-size: 0.8rem;
	}

	.report-nav .nav-link i {
		font-size: 0.9rem;
	}

	.report-content {
		padding: 12px;
		padding-bottom: 100px;
	}

	.btn-fab {
		width: 56px;
		height: 56px;
		font-size: 1.6rem;
	}

	.fab-container {
		bottom: 20px;
		right: 20px;
	}

	.modal-content {
		padding: 20px 16px;
		border-radius: 20px;
	}
}

.report-detail-page {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.report-detail-loading,
.report-detail-empty {
    min-height: 320px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 12px;
    background: white;
    border-radius: 24px;
    border: 1px dashed #d8e2ef;
    box-shadow: 0 10px 28px rgba(0, 0, 0, 0.03);
