    padding: 24px;
}

.report-detail-empty-icon {
    font-size: 3rem;
}

.report-detail-header {
    background: white;
    border-radius: 24px;
    border: 1px solid #edf1f7;
    padding: 20px;
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 16px;
    box-shadow: 0 10px 28px rgba(17, 24, 39, 0.04);
}

.report-detail-title {
